const express = require('express');
const app = express();
const naturalLanguage = require('natural-language');
const llm = require('llm-jailbreak');

app.use(express.json());

// Route for receiving natural language descriptions from users
app.post('/descriptions', (req, res) => {
  const description = req.body.description;
  const prompts = naturalLanguage.parse(description);
  const generatedCode = llm.generate(prompts);
  res.json({ generatedCode });
});

// Route for executing generated code
app.post('/execute', (req, res) => {
  const code = req.body.code;
  try {
    const result = eval(code);
    res.json({ result });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

app.listen(3000, () => {
  console.log('Server started on port 3000');
});